    30|export type IVXAIProviderMetadata = {
    31|  provider: 'chatgpt';
    32|  source: 'remote_api';
    33|  model: string;
    34|  endpoint: string | null;
    35|  runtime: 'vercel_ai_gateway';
    36|  ivxAI: {
    37|    architecture: 'ivx-ai';
    38|    phase: 'agent_runtime_v2';
    39|    layer: 'ivx_ai_runtime_wrapper';
    40|    module: string;
    41|    providerDependency: 'chatgpt_current_baseline';
    42|    requestId: string | null;
    43|    generatedAt: string;
    44|  };
    45|};
    46|
    47|export type IVXAITextResult = {
    48|  text: string;
    49|  usage: unknown;
    50|  providerMetadata: IVXAIProviderMetadata;
    51|};
    52|
    53|type IVXAIGatewayFailureContext = {
    54|  module: string;
    55|  requestId: string | null;
    56|  model: string;
    57|  endpoint: string | null;
    58|  status?: number | null;
    59|  responseBody?: unknown;
    60|};
    61|
    62|export type IVXAIConfigurationSnapshot = {
    63|  configured: boolean;
    64|  hasGatewayUrl: boolean;
    65|  hasGatewayApiKey: boolean;
    66|  model: string;
    67|  endpoint: string | null;
    68|  runtime: 'vercel_ai_gateway';
    69|  layer: 'ivx_ai_runtime_wrapper';
    70|  phase: 'agent_runtime_v2';
    71|};
    72|
    73|const GATEWAY_BASE_PATH = '/v3/ai';
    74|// Full multimodal model billed against the paid Vercel AI Gateway balance.
    75|// gpt-4o-mini is a free-tier model that Vercel rate-limits and is the weakest
    76|// vision model; gpt-4o gives real image + document analysis with no free-tier
    77|// caps. Override with IVX_AI_MODEL / PUBLIC_CHAT_MODEL / OPENAI_MODEL if needed.
    78|const DEFAULT_IVX_AI_MODEL = readTrimmed(process.env.IVX_AI_MODEL) || 'openai/gpt-4o';
    79|
    80|// Adaptive timeout floor / ceiling. Short prompts resolve fast (floor), large
    81|// reports get more headroom (ceiling). Tuned so a 12k-token report has ~90s
    82|// to complete instead of dying at the legacy 8s wall.
    83|const IVX_AI_TIMEOUT_FLOOR_MS = (() => {
    84|  const raw = Number.parseInt(readTrimmed(process.env.IVX_AI_GATEWAY_TIMEOUT_MS) || '15000', 10);
    85|  return Number.isFinite(raw) && raw > 0 ? raw : 15_000;
    86|})();
    87|const IVX_AI_TIMEOUT_CEIL_MS = (() => {
    88|  const raw = Number.parseInt(readTrimmed(process.env.IVX_AI_GATEWAY_TIMEOUT_CEIL_MS) || '120000', 10);
    89|  return Number.isFinite(raw) && raw > 0 ? raw : 120_000;
    90|})();
    91|
    92|/**
    93| * Compute an adaptive hard timeout based on the size of the work.
    94| *
    95| * Budget heuristics:
    96| *  - Base latency: floor (covers handshake + first-token latency)
    97| *  - Output budget: ~50ms per maxOutputToken (gpt-4o-mini sustains ~20 tok/s)
    98| *  - Prompt budget: ~2ms per prompt char (covers large context ingestion)
    99| * Clamped to [floor, ceiling].
   100| */
   101|export function computeAdaptiveTimeoutMs(input: {
   102|  promptChars: number;
   103|  maxOutputTokens: number | null | undefined;
   104|}): number {
   105|  const outputBudget = (input.maxOutputTokens ?? 1500) * 50;
   106|  const promptBudget = input.promptChars * 2;
   107|  const budget = IVX_AI_TIMEOUT_FLOOR_MS + outputBudget + promptBudget;
   108|  return Math.min(IVX_AI_TIMEOUT_CEIL_MS, Math.max(IVX_AI_TIMEOUT_FLOOR_MS, budget));
   109|}
   110|
   111|function runWithHardTimeout<T>(label: string, promise: Promise<T>, timeoutMs: number): Promise<T> {
   112|  return new Promise<T>((resolve, reject) => {
   113|    const timer = setTimeout(() => {
   114|      const err = new Error(`${label} timed out after ${timeoutMs}ms`);
   115|      err.name = 'IVXAIGatewayTimeoutError';
   116|      reject(err);
   117|    }, timeoutMs);
   118|    promise.then(
   119|      (value) => {
   120|        clearTimeout(timer);
   121|        resolve(value);
   122|      },
   123|      (error) => {
   124|        clearTimeout(timer);
   125|        reject(error);
   126|      },
   127|    );
   128|  });
   129|}
   130|
   131|function readTrimmed(value: unknown): string {
   132|  return typeof value === 'string' ? value.trim() : '';
   133|}
   134|
   135|function nowIso(): string {
   136|  return new Date().toISOString();
   137|}
   138|
   139|// Backend MUST talk directly to the canonical Vercel AI Gateway so the paid
   140|// AI_GATEWAY_API_KEY bearer reaches Vercel intact. Any client-facing proxy
   141|// (EXPO_PUBLIC_IVX_AI_GATEWAY_URL, e.g. ai.ivxholding.com) is intended for
   142|// the frontend only and may strip the Authorization header, which causes the
   143|// gateway to fall back to anonymous free-tier rate limits and return the
   144|// "Free tier requests on this model are rate-limited" 429 even when the
   145|// account has paid balance. The server-only override IVX_AI_GATEWAY_URL is
   146|// honored for advanced routing; otherwise we go direct to Vercel.
   147|function getIVXAIGatewayRootUrl(): string {
   148|  return readTrimmed(process.env.IVX_AI_GATEWAY_URL)
   149|    || 'https://ai-gateway.vercel.sh';
   150|}
   151|
   152|function getIVXAIGatewayApiKey(): string {
   153|  return readTrimmed(process.env.AI_GATEWAY_API_KEY);
   154|}
   155|
   156|function buildGatewayBaseUrl(rootUrl: string): string | null {
   157|  const gatewayRootUrl = readTrimmed(rootUrl).replace(/\/+$/, '');
   158|  if (!gatewayRootUrl) {
   159|    return null;
   160|  }
   161|
   162|  if (gatewayRootUrl.endsWith('/v3/ai') || gatewayRootUrl.endsWith(GATEWAY_BASE_PATH)) {
   163|    return gatewayRootUrl;
   164|  }
   165|
   166|  return new URL(GATEWAY_BASE_PATH, `${gatewayRootUrl}/`).toString().replace(/\/+$/, '');
   167|}
   168|
   169|function getGatewayBaseUrl(): string | null {
   170|  return buildGatewayBaseUrl(getIVXAIGatewayRootUrl());
   171|}
   172|
   173|function getGatewayBaseUrlCandidates(): string[] {
   174|  const configured = getGatewayBaseUrl();
   175|  const canonical = buildGatewayBaseUrl('https://ai-gateway.vercel.sh');
   176|  // Always include the canonical Vercel gateway as a fallback candidate so a
   177|  // misconfigured IVX_AI_GATEWAY_URL cannot strand the backend on a proxy that
   178|  // strips auth headers (which causes free-tier 429s on a paid account).
   179|  const candidates = [configured, canonical];
   180|
   181|  // If a Rork toolkit key is available, add the native Rork toolkit URL as a
   182|  // candidate. This lets the backend keep working when AI_GATEWAY_API_KEY is
   183|  // missing or when it is set to a rork_sk_* key (which cannot authenticate the
   184|  // Vercel gateway). The toolkit candidate is tried after the Vercel gateway
   185|  // and is handled by callRorkToolkitNative, which uses a direct fetch with the
   186|  // toolkit bearer.
   187|  const rorkToolkitKey = getRorkToolkitKey();
   188|  if (rorkToolkitKey) {
   189|    candidates.push(RORK_TOOLKIT_NATIVE_URL);
   190|  }
   191|
   192|  return [...new Set(candidates.filter((candidate): candidate is string => Boolean(candidate)))];
   193|}
   194|
   195|function ensureIVXAIGatewayEnvironment(): void {
   196|  const apiKey = getIVXAIGatewayApiKey();
   197|  const rorkToolkitKey = getRorkToolkitKey();
   198|  if (!apiKey && !rorkToolkitKey) {
   199|    throw new Error('IVX AI runtime is not configured.');
   200|  }
   201|
   202|  // When only a Rork toolkit key is available, set it as the gateway key so the
   203|  // Vercel AI SDK createGateway call has a bearer. The actual toolkit candidate
   204|  // is routed through callRorkToolkitNative, which uses a direct fetch with the
   205|  // same key.
   206|  if (!apiKey && rorkToolkitKey && !readTrimmed(process.env.AI_GATEWAY_API_KEY)) {
   207|    process.env.AI_GATEWAY_API_KEY = rorkToolkitKey;
   208|  } else if (!readTrimmed(process.env.AI_GATEWAY_API_KEY)) {
   209|    process.env.AI_GATEWAY_API_KEY = apiKey;
   210|  }
   211|}
   212|
   213|const RORK_TOOLKIT_NATIVE_URL = 'https://toolkit.rork.com/text/llm/';
   214|
   215|function isRorkToolkitBaseUrl(baseUrl: string): boolean {
   216|  return readTrimmed(baseUrl).includes('toolkit.rork.com');
   217|}
   218|
   219|function getRorkToolkitKey(): string {
   220|  return readTrimmed(process.env.RORK_TOOLKIT_SECRET_KEY)
   221|    || readTrimmed(process.env.EXPO_PUBLIC_RORK_TOOLKIT_SECRET_KEY)
   222|    || (readTrimmed(process.env.AI_GATEWAY_API_KEY).startsWith('rork_sk_') ? readTrimmed(process.env.AI_GATEWAY_API_KEY) : '');
   223|}
   224|
   225|type RorkToolkitNativeResult = {
   226|  text: string;
   227|  usage: unknown;
   228|};
   229|
   230|async function callRorkToolkitNative(input: {
   231|  model: string;
   232|  system: string;
   233|  prompt: string;
   234|  messages: IVXAITextMessage[];
   235|  maxOutputTokens?: number;
   236|  timeoutMs: number;
   237|  apiKey: string;
   238|}): Promise<RorkToolkitNativeResult> {
   239|  const apiKey = input.apiKey;
   240|  if (!apiKey) {
   241|    throw new Error('rork_toolkit native path not configured: missing rork_sk key');
   242|  }
   243|
   244|  const model = input.model;
   245|  const url = RORK_TOOLKIT_NATIVE_URL;
   246|  const messages: { role: 'user' | 'assistant'; content: string }[] = [];
   247|  if (input.messages.length > 0) {
   248|    for (const m of input.messages) messages.push({ role: m.role, content: m.content });
   249|  } else if (input.prompt) {
   250|    messages.push({ role: 'user', content: input.prompt });
   251|  }
   252|
   253|  const controller = new AbortController();
   254|  const timer = setTimeout(() => controller.abort(), input.timeoutMs);
   255|  const startedAt = Date.now();
   256|  try {
   257|    const response = await fetch(url, {
   258|      method: 'POST',
   259|      headers: {
   260|        'Content-Type': 'application/json',
   261|        Authorization: `Bearer ${apiKey}`,
   262|      },
   263|      body: JSON.stringify({
   264|        model,
   265|        messages,
   266|        max_tokens: input.maxOutputTokens ?? 1024,
   267|      }),
   268|      signal: controller.signal,
   269|    });
   270|    if (!response.ok) {
   271|      throw new Error(`rork_toolkit native status=${response.status}`);
   272|    }
   273|    const json = await response.json() as { completion?: string };
   274|    const text = readTrimmed(json.completion ?? '');
   275|    if (!text) throw new Error('rork_toolkit native empty response');
   276|    return { text, usage: null };
   277|  } finally {
   278|    console.log('[IVXAI] Rork toolkit native call completed in', Date.now() - startedAt, 'ms');
   279|    clearTimeout(timer);
   280|  }
   281|}
   282|
   283|function readRecord(value: unknown): Record<string, unknown> {
   284|  return typeof value === 'object' && value !== null ? value as Record<string, unknown> : {};
   285|}
   286|
   287|function extractGatewayFailureContext(error: unknown): { status: number | null; responseBody: unknown } {
   288|  const record = readRecord(error);
   289|  const response = readRecord(record.response);
   290|  const cause = readRecord(record.cause);
   291|  const status = typeof record.statusCode === 'number'
   292|    ? record.statusCode
   293|    : typeof record.status === 'number'
   294|      ? record.status
   295|      : typeof record.responseStatus === 'number'
   296|        ? record.responseStatus
   297|        : typeof response.status === 'number'
   298|          ? response.status
   299|          : typeof cause.status === 'number'
   300|            ? cause.status
   301|            : null;
   302|  const responseBody = record.responseBody
   303|    ?? response.body
   304|    ?? response.data
   305|    ?? record.data
   306|    ?? record.body
   307|    ?? cause.responseBody
   308|    ?? cause.body
   309|    ?? null;
   310|  return { status, responseBody };
   311|}
   312|
   313|function normalizeGatewayFailure(error: unknown, context: IVXAIGatewayFailureContext): Error {
   314|  const message = error instanceof Error ? error.message : 'Gateway request failed';
   315|  const body = typeof context.responseBody === 'string'
   316|    ? context.responseBody.slice(0, 600)
   317|    : context.responseBody && typeof context.responseBody === 'object'
   318|      ? JSON.stringify(context.responseBody).slice(0, 600)
   319|      : null;
   320|  const detail = [
   321|    `IVX AI gateway request failed for ${context.module}.`,
   322|    `endpoint=${context.endpoint ?? 'unresolved'}`,
   323|    `model=${context.model}`,
   324|    context.status ? `status=${context.status}` : null,
   325|    `providerError=${message}`,
   326|    body ? `responseBody=${body}` : null,
   327|  ].filter(Boolean).join(' ');
   328|  const normalized = new Error(detail);
   329|  normalized.name = 'IVXAIGatewayRequestError';
   330|  return normalized;
   331|}
   332|
   333|function normalizeMessages(messages: IVXAITextMessage[] | undefined): IVXAITextMessage[] {
   334|  return (messages ?? [])
   335|    .map((message) => ({
   336|      role: message.role === 'assistant' ? 'assistant' as const : 'user' as const,
   337|      content: readTrimmed(message.content),
   338|    }))
   339|    .filter((message) => message.content.length > 0);
   340|}
   341|
   342|export function resolveIVXAIModel(explicitModel?: string | null, envCandidates: string[] = []): string {
   343|  const explicit = readTrimmed(explicitModel);
   344|  if (explicit) {
   345|    return explicit;
   346|  }
   347|
   348|  for (const envName of envCandidates) {
   349|    const candidate = readTrimmed(process.env[envName]);
   350|    if (candidate) {
   351|      return candidate;
   352|    }
   353|  }
   354|
   355|  return DEFAULT_IVX_AI_MODEL;
   356|}
   357|
   358|export function getIVXAIEndpoint(model: string = DEFAULT_IVX_AI_MODEL): string | null {
   359|  const baseUrl = getGatewayBaseUrl();
   360|  if (!baseUrl) {
   361|    return null;
   362|  }
   363|
   364|  return `${baseUrl}/${model}`;
   365|}
   366|
   367|export function isIVXAIConfigured(): boolean {
   368|  return getIVXAIGatewayRootUrl().length > 0 && getIVXAIGatewayApiKey().length > 0;
   369|}
   370|
   371|export function getIVXAIConfigurationSnapshot(model: string = DEFAULT_IVX_AI_MODEL): IVXAIConfigurationSnapshot {
   372|  const hasGatewayUrl = getIVXAIGatewayRootUrl().length > 0;
   373|  const hasGatewayApiKey = getIVXAIGatewayApiKey().length > 0;
   374|  return {
   375|    configured: hasGatewayUrl && hasGatewayApiKey,
   376|    hasGatewayUrl,
   377|    hasGatewayApiKey,
   378|    model,
   379|    endpoint: getIVXAIEndpoint(model),
   380|    runtime: 'vercel_ai_gateway',
   381|    layer: 'ivx_ai_runtime_wrapper',
   382|    phase: 'agent_runtime_v2',
   383|  };
   384|}
   385|
   386|export async function requestIVXAIText(input: {
   387|  module: IVXAIModule;
   388|  requestId?: string | null;
   389|  model?: string | null;
   390|  system?: string | null;
   391|  prompt?: string | null;
   392|  messages?: IVXAITextMessage[];
   393|  images?: IVXAIImageAttachment[];
   394|  files?: IVXAIFileAttachment[];
   395|  maxOutputTokens?: number;
   396|}): Promise<IVXAITextResult> {
   397|  const model = resolveIVXAIModel(input.model);
   398|  const endpoint = getIVXAIEndpoint(model);
   399|  const messages = normalizeMessages(input.messages);
   400|  const prompt = readTrimmed(input.prompt);
   401|  const system = readTrimmed(input.system);
   402|  const images = (input.images ?? [])
   403|    .map((img) => ({ url: readTrimmed(img.url), mimeType: readTrimmed(img.mimeType ?? '') || null }))
   404|    .filter((img) => img.url.length > 0);
   405|  const files = (input.files ?? []).filter(
   406|    (file) => readTrimmed(file.mediaType).length > 0 && file.data != null,
   407|  );
   408|
   409|  if (!prompt && messages.length === 0) {
   410|    throw new Error('IVX AI request requires a prompt or messages.');
   411|  }
   412|
   413|  const baseUrlCandidates = getGatewayBaseUrlCandidates();
   414|  if (baseUrlCandidates.length === 0) {
   415|    throw new Error('IVX AI runtime is not configured.');
   416|  }
   417|
   418|  console.log('[IVXAI] Routing request through IVX AI Phase 1 wrapper:', {
   419|    module: input.module,
   420|    requestId: input.requestId ?? null,
   421|    model,
   422|    endpoint,
   423|    baseUrlCandidates,
   424|    hasSystem: system.length > 0,
   425|    promptLength: prompt.length,
   426|    messageCount: messages.length,
   427|    authKeySource: 'AI_GATEWAY_API_KEY',
   428|    requestShape: messages.length > 0 ? 'messages' : 'prompt',
   429|    maxOutputTokens: input.maxOutputTokens ?? null,
   430|    phase: 'agent_runtime_v2',
   431|    layer: 'ivx_ai_runtime_wrapper',
   432|  });
   433|
   434|  // Adaptive timeout + queue gating: long prompts/reports get more time and a
   435|  // dedicated lane so they cannot block normal chat under contention.
   436|  const promptChars = prompt.length + system.length + messages.reduce((sum, m) => sum + m.content.length, 0);
   437|  const adaptiveTimeoutMs = computeAdaptiveTimeoutMs({ promptChars, maxOutputTokens: input.maxOutputTokens });
   438|  const queueLane: IVXAIQueueLane = classifyRequestLane({ promptChars, maxOutputTokens: input.maxOutputTokens });
   439|  const queueSlot = await acquireAIQueueSlot(queueLane);
   440|  const callStartedAt = Date.now();
   441|
   442|  let result: Awaited<ReturnType<typeof generateText>> | null = null;
   443|  let lastError: unknown = null;
   444|  let lastFailure: { status: number | null; responseBody: unknown } = { status: null, responseBody: null };
   445|  let successfulBaseUrl = baseUrlCandidates[0];
   446|  let retryCount = 0;
   447|
   448|  for (const baseURL of baseUrlCandidates) {
   449|    ensureIVXAIGatewayEnvironment();
   450|    try {
   451|      if (isRorkToolkitBaseUrl(baseURL)) {
   452|        const rorkResult = await runWithHardTimeout(
   453|          'Rork toolkit native',
   454|          callRorkToolkitNative({
   455|            model,
   456|            system,
   457|            prompt,
   458|            messages,
   459|            maxOutputTokens: input.maxOutputTokens,
   460|            timeoutMs: adaptiveTimeoutMs,
   461|            apiKey: getRorkToolkitKey(),
   462|          }),
   463|          adaptiveTimeoutMs,
   464|        );
   465|        result = rorkResult as Awaited<ReturnType<typeof generateText>>;
   466|        successfulBaseUrl = baseURL;
   467|        break;
   468|      }
   469|
   470|      const gatewayProvider = createGateway({
   471|        apiKey: getIVXAIGatewayApiKey(),
   472|        baseURL,
   473|      });
   474|      const callTimeoutMs = adaptiveTimeoutMs;
   475|      if (images.length > 0 || files.length > 0) {
   476|        // Multimodal request: build a single user message with text + image/file
   477|        // parts so multimodal models (gpt-4o family for images/PDF OCR, video-
   478|        // capable models for video) can actually see the attachments.
   479|        const baseMessages = messages.length > 0
   480|          ? messages.slice(0, -1)
   481|          : [];
   482|        const lastTextMessage = messages.length > 0 ? messages[messages.length - 1] : null;
   483|        const userText = readTrimmed(
   484|          (lastTextMessage && lastTextMessage.role === 'user' ? lastTextMessage.content : '') || prompt
   485|        ) || 'Describe the attached file(s).';
   486|        const multimodalUser = {
   487|          role: 'user' as const,
   488|          content: [
   489|            { type: 'text' as const, text: userText },
   490|            ...images.map((img) => ({ type: 'image' as const, image: img.url })),
   491|            ...files.map((file) => ({ type: 'file' as const, data: file.data, mediaType: file.mediaType })),
   492|          ],
   493|        };
   494|        const finalMessages = lastTextMessage && lastTextMessage.role === 'user'
   495|          ? [...baseMessages, multimodalUser]
   496|          : [...messages, multimodalUser];
   497|        result = await runWithHardTimeout('IVX AI gateway (multimodal)', generateText({
   498|          model: gatewayProvider(model),
   499|          system: system.length > 0 ? system : undefined,
   500|          maxOutputTokens: input.maxOutputTokens,
   501|          // eslint-disable-next-line @typescript-eslint/no-explicit-any
   502|          messages: finalMessages as any,
   503|        }), callTimeoutMs);
   504|      } else {
   505|        result = messages.length > 0
   506|          ? await runWithHardTimeout('IVX AI gateway (messages)', generateText({
   507|              model: gatewayProvider(model),
   508|              system: system.length > 0 ? system : undefined,
   509|              maxOutputTokens: input.maxOutputTokens,
   510|              messages,
   511|            }), callTimeoutMs)
   512|          : await runWithHardTimeout('IVX AI gateway (prompt)', generateText({
   513|              model: gatewayProvider(model),
   514|              system: system.length > 0 ? system : undefined,
   515|              maxOutputTokens: input.maxOutputTokens,
   516|              prompt,
   517|            }), callTimeoutMs);
   518|      }
   519|      successfulBaseUrl = baseURL;
   520|      break;
   521|    } catch (error) {
   522|      retryCount += 1;
   523|      const failure = extractGatewayFailureContext(error);
   524|      lastError = error;
   525|      lastFailure = failure;
   526|      console.error('[IVXAI] Gateway request failed:', {
   527|        module: input.module,
   528|        requestId: input.requestId ?? null,
   529|        model,
   530|            endpoint: `${baseURL}/${model}`,
   531|        status: failure.status,
   532|        error: error instanceof Error ? error.message : 'Gateway request failed',
   533|        responseBodyType: typeof failure.responseBody,
   534|        responseBodyPreview: typeof failure.responseBody === 'string'
   535|          ? failure.responseBody.slice(0, 400)
   536|          : failure.responseBody && typeof failure.responseBody === 'object'
