import { resolveIVXIdentityAnswer, detectIVXIdentityQuestion } from './backend/services/ivx-ia-identity-brain';

const tests = [
  { msg: "what is your name", expect: "name", shouldIntercept: true },
  { msg: "who created you", expect: "creator", shouldIntercept: true },
  { msg: "who is your owner", expect: "owner", shouldIntercept: true },
  { msg: "what is IVX", expect: "what_is_ivx", shouldIntercept: true },
  { msg: "What is Casa Rosario and what are the returns?", expect: "ivx_project", shouldIntercept: false },
  { msg: "tell me about the deal", expect: "ivx_project", shouldIntercept: false },
  { msg: "how do I invest", expect: "ivx_investment", shouldIntercept: false },
  { msg: "what is the ROI", expect: "ivx_investment", shouldIntercept: false },
  { msg: "casa rosario", expect: "ivx_project", shouldIntercept: false },
  { msg: "jv deal", expect: "ivx_project", shouldIntercept: false },
  { msg: "What are the returns for Casa Rosario?", expect: "ivx_project", shouldIntercept: false },
];

let pass = 0, fail = 0;
for (const t of tests) {
  const detected = detectIVXIdentityQuestion(t.msg);
  const answer = resolveIVXIdentityAnswer(t.msg);
  const intercepted = answer !== null;
  const ok = detected === t.expect && intercepted === t.shouldIntercept;
  if (ok) { pass++; console.log(`PASS: "${t.msg}" → ${detected}, intercepted=${intercepted}`); }
  else { fail++; console.log(`FAIL: "${t.msg}" → detected=${detected} (expected ${t.expect}), intercepted=${intercepted} (expected ${t.shouldIntercept})`); }
}
console.log(`\n${pass}/${pass+fail} passed`);
process.exit(fail > 0 ? 1 : 0);
EOF
timeout 30 bun run /tmp/test-identity-fix.ts 2>&1

